class Solution(object):
    def longestBalanced(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            evens, odds = set(), set()
            for j in range(i, n):
                v = nums[j]
                if v % 2 == 0:
                    evens.add(v)
                else:
                    odds.add(v)
                if len(evens) == len(odds):
                    best = max(best, j - i + 1)
        return best
